SELECT ?volcanoLabel WHERE {
  ?eruption wdt:P31 wd:Q15049;
            wdt:P159 ?volcano;
            wdt:P585 ?date.
  ?volcano wdt:P131 wd:Q34.
  FILTER (?date >= "2010-01-01T00:00:00Z"^^xsd:dateTime &&
          ?date < "2011-01-01T00:00:00Z"^^xsd:dateTime).
  ?volcano rdfs:label ?volcanoLabel.
  FILTER (lang(?volcanoLabel) = "en").
}

